#!/usr/bin/env node

/**
 * Build the cross-platform Discover seed module from the reviewed Sloe
 * Kitchen content pack. The generated file stays under `src/lib` because the
 * mobile Metro build deliberately watches shared source, not the repository's
 * content directory.
 */

import { readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const REPO_ROOT = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const CONTENT_DIR = resolve(REPO_ROOT, "content/sloe-kitchen/v1");
const OUTPUT_PATH = resolve(REPO_ROOT, "src/lib/recipes/sloeKitchenSeedData.ts");

const recipes = readJson("recipes.json").recipes;
const nutrition = readJson("nutrition.json").recipes;
const hostedImages = readJson("hosted-images.json").images;
const provenance = readJson("image-provenance.json").assets;

assertMatchingSlugs("nutrition", recipes, nutrition);
assertMatchingSlugs("hosted images", recipes, hostedImages);
assertMatchingSlugs("image provenance", recipes, provenance);

const nutritionBySlug = new Map(nutrition.map((item) => [item.slug, item]));
const imageBySlug = new Map(hostedImages.map((item) => [item.slug, item]));
const provenanceBySlug = new Map(provenance.map((item) => [item.slug, item]));

const seeds = recipes.map((recipe) => {
  const verifiedNutrition = nutritionBySlug.get(recipe.slug);
  const hostedImage = imageBySlug.get(recipe.slug);
  const imageProvenance = provenanceBySlug.get(recipe.slug);
  if (verifiedNutrition.status !== "verified") {
    throw new Error(`${recipe.slug} nutrition is not verified`);
  }

  return {
    id: `seed-v2-${recipe.cluster}-${recipe.slug}`,
    cluster: recipe.cluster,
    title: recipe.title,
    heroImageUrl: hostedImage.url,
    totalTimeMin: recipe.prepMinutes + recipe.cookMinutes,
    prepTimeMin: recipe.prepMinutes,
    cookTimeMin: recipe.cookMinutes,
    servings: recipe.servings,
    kcalPerPortion: verifiedNutrition.perServing.calories,
    proteinG: verifiedNutrition.perServing.protein,
    carbsG: verifiedNutrition.perServing.carbs,
    fatG: verifiedNutrition.perServing.fat,
    fiberG: verifiedNutrition.perServing.fiberG,
    sugarG: verifiedNutrition.perServing.sugarG,
    sodiumMg: verifiedNutrition.perServing.sodiumMg,
    ingredients: recipe.ingredients.map((ingredient) => ({
      name: ingredient.preparation
        ? `${ingredient.item}, ${ingredient.preparation}`
        : ingredient.item,
      grams: ingredient.grams,
    })),
    steps: recipe.steps,
    shortDescription: recipe.shortDescription,
    tags: recipe.tags,
    allergens: recipe.allergens,
    nutritionVerification: {
      status: "verified",
      engine: "verifyIngredients",
      minIngredientConfidence:
        verifiedNutrition.verification.minIngredientConfidence,
      avgIngredientConfidence:
        verifiedNutrition.verification.avgIngredientConfidence,
    },
    attribution: {
      author: "Sloe Kitchen",
      origin: "ai-generated-edited",
      imageSource: {
        provider: "openai-imagegen",
        url: hostedImage.url,
        sourceArtifact: imageProvenance.sourceArtifact,
      },
      notes: recipe.culinaryBasis,
    },
  };
});

const output = `/**
 * Generated by scripts/build-sloe-kitchen-discover-seed.mjs.
 * Edit content/sloe-kitchen/v1/* and rerun the generator; do not hand-edit.
 */
import type { SeedRecipe } from "./seedRecipesV2";

export const SLOE_KITCHEN_SEED_DATA = ${JSON.stringify(seeds, null, 2)} as const satisfies ReadonlyArray<SeedRecipe>;
`;

writeFileSync(OUTPUT_PATH, output);
console.log(`Wrote ${OUTPUT_PATH} with ${seeds.length} recipes`);

function readJson(filename) {
  return JSON.parse(readFileSync(resolve(CONTENT_DIR, filename), "utf8"));
}

function assertMatchingSlugs(label, canonical, candidate) {
  const expected = canonical.map((item) => item.slug).sort();
  const actual = candidate.map((item) => item.slug).sort();
  if (JSON.stringify(expected) !== JSON.stringify(actual)) {
    throw new Error(`${label} slugs do not match recipes.json`);
  }
}
